import React, { useState, useEffect } from 'react';
import axios from '../utils/axiosConfig';
import { toast } from 'react-toastify';
import { styles } from '../styles/styles';
import { API_URL } from '../constants';
import MovieCard from '../components/MovieCard';
import FilterSection from '../components/FilterSection';
import LoadingState from '../components/LoadingState';
import EmptyState from '../components/EmptyState';
import RecommendationCard from '../components/RecommendationCard';
import { collaborativeFilterService } from '../services/collaborativeFilterService';

function HomePage() {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [selectedGenre, setSelectedGenre] = useState('All');
  const [sortBy, setSortBy] = useState('latest');
  const [collaborativeRecs, setCollaborativeRecs] = useState([]);
  const [showCollaborativeRecs, setShowCollaborativeRecs] = useState(false);
  const [userId, setUserId] = useState(localStorage.getItem('userId') || '');
  
  // Initialize with a default user ID if none exists
  useEffect(() => {
    if (!userId) {
      const newUserId = `user_${Date.now()}`;
      setUserId(newUserId);
      localStorage.setItem('userId', newUserId);
    }
  }, [userId]);

  useEffect(() => {
    fetchMovies();
  }, [selectedGenre, sortBy]);

  useEffect(() => {
    if (userId && showCollaborativeRecs) {
      fetchCollaborativeRecommendations();
    }
  }, [userId, showCollaborativeRecs]);

  const fetchCollaborativeRecommendations = async () => {
    try {
      setLoading(true);
      const response = await collaborativeFilterService.getUserRecommendations(userId);
      setCollaborativeRecs(response.recommendations || []);
    } catch (error) {
      console.error('Error fetching collaborative recommendations:', error);
      toast.error('Failed to load personalized recommendations');
    } finally {
      setLoading(false);
    }
  };

  const fetchMovies = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (selectedGenre !== 'All') params.append('genre', selectedGenre);
      if (sortBy === 'rating') params.append('sort', 'rating');
      if (sortBy === 'year') params.append('sort', 'year');
      if (sortBy === 'title') params.append('sort', 'title');

      const response = await axios.get(`${API_URL}/movies?${params}`);
      setMovies(response.data);
    } catch (error) {
      toast.error('Failed to fetch movies');
    } finally {
      setLoading(false);
    }
  };

  const filteredMovies = movies.filter(movie =>
    movie.title.toLowerCase().includes(search.toLowerCase()) ||
    movie.director.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div style={styles.container}>
      <div style={styles.heroSection}>
        <h1 style={styles.heroTitle}>Discover Amazing Movies</h1>
        <p style={styles.heroSubtitle}>
          Personalized recommendations based on your preferences
        </p>
      </div>

      {/* Toggle for collaborative filtering */}
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        marginBottom: '20px',
        gap: '10px'
      }}>
        <button
          onClick={() => setShowCollaborativeRecs(!showCollaborativeRecs)}
          style={{
            padding: '8px 16px',
            backgroundColor: showCollaborativeRecs ? '#e94560' : '#f0f0f0',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer',
            color: showCollaborativeRecs ? 'white' : '#333',
            fontWeight: '500'
          }}
        >
          {showCollaborativeRecs ? 'Hide Recommendations' : 'Show Personalized Recommendations'}
        </button>
        <span style={{ alignSelf: 'center', fontSize: '14px', color: '#666' }}>
          User ID: {userId}
        </span>
      </div>

      {/* Collaborative Recommendations Section */}
      {showCollaborativeRecs && (
        <div style={{ marginBottom: '40px' }}>
          <h2 style={{ 
            textAlign: 'center', 
            color: '#e94560', 
            marginBottom: '20px',
            fontSize: '24px'
          }}>
            Recommended For You
          </h2>
          
          {loading && collaborativeRecs.length === 0 ? (
            <LoadingState message="Loading personalized recommendations..." />
          ) : collaborativeRecs.length === 0 ? (
            <EmptyState message="Rate some movies to get personalized recommendations!" />
          ) : (
            <div style={styles.moviesGrid}>
              {collaborativeRecs.map(movie => (
                <RecommendationCard key={`rec-${movie._id}`} movie={movie} />
              ))}
            </div>
          )}
        </div>
      )}

      <FilterSection
        search={search}
        setSearch={setSearch}
        selectedGenre={selectedGenre}
        setSelectedGenre={setSelectedGenre}
        sortBy={sortBy}
        setSortBy={setSortBy}
      />

      {loading && !showCollaborativeRecs ? (
        <LoadingState message="Loading movies..." />
      ) : filteredMovies.length === 0 && !showCollaborativeRecs ? (
        <EmptyState message="No movies found. Check back later!" />
      ) : (
        <div style={styles.moviesGrid}>
          {filteredMovies.map(movie => (
            <MovieCard key={movie._id} movie={movie} />
          ))}
        </div>
      )}
    </div>
  );
}

export default HomePage;
